import React from 'react';

const NowPlaying = ({ track, isPlaying, onTogglePlay, onClose }) => {
    if (!track) return null; // Дополнительная проверка

    return (
        <div className="now-playing-bar">
            <div className="track-meta">
                <div className="track-details">
                    <strong>{track.title}</strong>
                    <span>{track.artist}</span>
                </div>
                <button onClick={onTogglePlay} className="play-btn">
                    {isPlaying ? '⏸️ Пауза' : '▶️ Слушать'}
                </button>
                <button onClick={onClose} className="close-btn">✖</button>
            </div>
            {/* Условное отображение "эффекта эквалайзера" */}
            {isPlaying && <div className="equalizer">🎵 🎵 🎵</div>}
        </div>
    );
};

export default NowPlaying;
